# 输入获取
nums = list(map(int, input().split(",")))


# 算法入口
def getResult():
    n = len(nums)

    # leftFree[i] 表示第i个车位的左边空闲车位个数
    leftFree = [0]*n
    for i in range(n):
        if nums[i] == 1:
            continue

        if nums[i-1] == 0:
            leftFree[i] = leftFree[i-1] + 1
        else:
            leftFree[i] = 0

    # rightFree[i] 表示第i个车位的右边空闲车位个数
    rightFree = [0]*n
    for i in range(n-2, -1, -1):
        if nums[i] == 1:
            continue

        if nums[i+1] == 0:
            rightFree[i] = rightFree[i+1] + 1
        else:
            rightFree[i] = 0

    # 如果第0个车位是空闲车位,那么第0个车位的最大距离就是它右边的空闲车位个数
    # 如果第n-1个车位是空闲车位,那么第n-1个车位的最大安全距离就是它左边的空闲车位个数
    ans = max(rightFree[0], leftFree[n-1])

    # 对于第i个车位&#xff08;i取值1~n-2&#xff09;,其最大距离取min(leftFree[i], rightFree[i])
    for i in range(1, n-1):
        if nums[i] == 1:
            continue

        ans = max(ans, min(leftFree[i], rightFree[i]))

    # ans记录的空闲车位数,转化为距离要+1
    return ans + 1


# 算法调用
print(getResult())
